import{_ as d,o as e,c as o,a2 as c}from"./chunks/framework.CuEaBji2.js";const h=JSON.parse('{"title":"环境变量速查","description":"","frontmatter":{},"headers":[],"relativePath":"reference/environment-variables.md","filePath":"reference/environment-variables.md","lastUpdated":1782021666000}'),r={name:"reference/environment-variables.md"};function a(E,t,_,s,n,i){return e(),o("div",null,[...t[0]||(t[0]=[c(`<h1 id="环境变量速查" tabindex="-1">环境变量速查 <a class="header-anchor" href="#环境变量速查" aria-label="Permalink to &quot;环境变量速查&quot;">​</a></h1><p>控制面和 Agent 通过环境变量配置。时间值使用 Go duration 格式（<code>500ms</code>、<code>5s</code>、<code>2m</code>）。大多数 <code>NRE_*</code> 变量有旧版别名，旧配置可以继续使用。</p><h2 id="快速索引" tabindex="-1">快速索引 <a class="header-anchor" href="#快速索引" aria-label="Permalink to &quot;快速索引&quot;">​</a></h2><table tabindex="0"><thead><tr><th>你想做的事</th><th>对应变量</th></tr></thead><tbody><tr><td>设置面板密码</td><td><code>API_TOKEN</code>（必填）</td></tr><tr><td>设置时区</td><td><code>NRE_TIMEZONE</code>（国内填 <code>Asia/Shanghai</code>）</td></tr><tr><td>设置公网访问地址</td><td><code>NRE_PUBLIC_URL</code></td></tr><tr><td>设置 HTTP 临时随机面板入口</td><td><code>NRE_PANEL_PUBLIC_PATH</code></td></tr><tr><td>切换数据库</td><td><code>NRE_DATABASE_DRIVER</code> + <code>NRE_DATABASE_DSN</code></td></tr><tr><td>开启 Cloudflare DNS 验证</td><td><code>ACME_DNS_PROVIDER=cf</code> + <code>CF_TOKEN</code></td></tr><tr><td>关闭 WireGuard</td><td><code>NRE_WIREGUARD_ENABLED=false</code></td></tr><tr><td>关闭流量统计</td><td><code>NRE_TRAFFIC_STATS_ENABLED=false</code></td></tr><tr><td>Agent 注册令牌</td><td><code>MASTER_REGISTER_TOKEN</code></td></tr></tbody></table><hr><h2 id="控制面" tabindex="-1">控制面 <a class="header-anchor" href="#控制面" aria-label="Permalink to &quot;控制面&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>作用</th></tr></thead><tbody><tr><td><code>NRE_PANEL_TOKEN</code>（别名 <code>API_TOKEN</code>）</td><td><strong>必填</strong></td><td>网页界面和 API 认证的登录令牌。示例占位值会被拒绝启动。</td></tr><tr><td><code>NRE_REGISTER_TOKEN</code>（别名 <code>MASTER_REGISTER_TOKEN</code>、<code>PANEL_REGISTER_TOKEN</code>、<code>API_TOKEN</code>）</td><td>未设置时依次尝试 <code>MASTER_REGISTER_TOKEN</code>、<code>PANEL_REGISTER_TOKEN</code>、<code>API_TOKEN</code></td><td>Agent 向控制面注册时使用的令牌。示例占位值会被拒绝启动。</td></tr><tr><td><code>NRE_CONTROL_PLANE_ADDR</code>（别名 <code>PANEL_BACKEND_HOST</code> + <code>PANEL_BACKEND_PORT</code>）</td><td><code>0.0.0.0:8080</code></td><td>控制面监听的地址。</td></tr><tr><td><code>NRE_PUBLIC_URL</code></td><td>空</td><td>控制面公网 URL，例如 <code>https://panel.example.com</code>。设置后 join script 和 Agent 更新包 URL 会优先使用该值。</td></tr><tr><td><code>NRE_PANEL_PUBLIC_PATH</code></td><td>空</td><td>无域名 HTTP 临时部署时的面板入口路径，例如 <code>/panel-a1b2c3d4</code>。设置后根路径不再直接服务面板；它不能替代 token 和 HTTPS。</td></tr><tr><td><code>NRE_TRUST_FORWARDED_HEADERS</code></td><td><code>false</code></td><td>是否信任上游反代设置的 <code>X-Forwarded-*</code> 头。仅在反代会清洗并重写这些头时开启。</td></tr><tr><td><code>NRE_CONTROL_PLANE_DATA_DIR</code>（别名 <code>PANEL_DATA_ROOT</code>）</td><td><code>/opt/nginx-reverse-emby/panel/data</code></td><td>SQLite 数据库和运行时数据的目录。</td></tr><tr><td><code>NRE_FRONTEND_DIST_DIR</code>（别名 <code>PANEL_FRONTEND_DIST_DIR</code>）</td><td><code>/opt/nginx-reverse-emby/panel/frontend/dist</code></td><td>存放构建好的前端文件的目录。</td></tr><tr><td><code>NRE_PUBLIC_AGENT_ASSETS_DIR</code>（别名 <code>PANEL_PUBLIC_AGENT_ASSETS_DIR</code>）</td><td><code>/opt/.../public/agent-assets</code></td><td>公共代理资源的目录（加入脚本、二进制文件）。</td></tr><tr><td><code>NRE_ENABLE_LOCAL_AGENT</code>（别名 <code>MASTER_LOCAL_AGENT_ENABLED</code>）</td><td><code>true</code></td><td>是否在控制面节点上运行内置的 <code>local</code> Agent。</td></tr><tr><td><code>NRE_LOCAL_AGENT_ID</code>（别名 <code>MASTER_LOCAL_AGENT_ID</code>）</td><td><code>local</code></td><td>内置本地代理的标识符。</td></tr><tr><td><code>NRE_LOCAL_AGENT_NAME</code>（别名 <code>MASTER_LOCAL_AGENT_NAME</code>）</td><td><code>local</code></td><td>内置本地代理的显示名称。</td></tr><tr><td><code>NRE_TIMEZONE</code></td><td><code>UTC</code></td><td>面板使用的时区（IANA 格式），用于每日/每月流量汇总和计费周期边界。</td></tr><tr><td><code>NRE_HEARTBEAT_INTERVAL</code></td><td><code>30s</code></td><td>从控制面角度的心跳间隔。（Agent 默认是 <code>10s</code>；见下面的 Agent 部分。）</td></tr><tr><td><code>NRE_PROJECT_URL</code></td><td>空</td><td>项目主页 URL，显示在版本信息中。</td></tr></tbody></table><hr><h2 id="数据库" tabindex="-1">数据库 <a class="header-anchor" href="#数据库" aria-label="Permalink to &quot;数据库&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>作用</th></tr></thead><tbody><tr><td><code>NRE_DATABASE_DRIVER</code></td><td><code>sqlite</code></td><td>数据库驱动：<code>sqlite</code>、<code>postgres</code> 或 <code>mysql</code>。</td></tr><tr><td><code>NRE_DATABASE_DSN</code></td><td>空</td><td>数据库连接字符串。对于 SQLite，如果为空，默认为 <code>NRE_CONTROL_PLANE_DATA_DIR/panel.db</code>。</td></tr></tbody></table><p><strong>PostgreSQL 示例：</strong></p><div class="language-ini vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NRE_DATABASE_DRIVER</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=postgres</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NRE_DATABASE_DSN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=postgres://nre:nre@postgres:5432/nre?</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">sslmode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=disable</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>MySQL 示例：</strong></p><div class="language-ini vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NRE_DATABASE_DRIVER</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=mysql</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NRE_DATABASE_DSN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=nre:nre@tcp(mysql:3306)/nre?</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">parseTime</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true&amp;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">charset</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=utf8mb4</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h2 id="证书-acme" tabindex="-1">证书 / ACME <a class="header-anchor" href="#证书-acme" aria-label="Permalink to &quot;证书 / ACME&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>作用</th></tr></thead><tbody><tr><td><code>ACME_DNS_PROVIDER</code></td><td>空</td><td>DNS 验证提供商。目前支持 <code>cf</code>（Cloudflare）。设置为 <code>cf</code> 并提供有效令牌以启用 DNS-01。</td></tr><tr><td><code>CLOUDFLARE_DNS_API_TOKEN</code>（别名 <code>CF_DNS_API_TOKEN</code>、<code>CF_TOKEN</code>、<code>CF_Token</code>）</td><td>空</td><td>用于 DNS-01 验证的 Cloudflare API 令牌。</td></tr><tr><td><code>CLOUDFLARE_ZONE_API_TOKEN</code>（别名 <code>CF_ZONE_API_TOKEN</code>）</td><td>空</td><td>可选的 Cloudflare 区域令牌。</td></tr><tr><td><code>NRE_ACME_EMAIL</code></td><td>空</td><td>ACME 账户注册用的电子邮件地址。</td></tr><tr><td><code>NRE_ACME_DIRECTORY_URL</code></td><td>Let&#39;s Encrypt 生产环境</td><td>ACME 目录 URL。</td></tr><tr><td><code>NRE_MANAGED_CERT_RENEW_INTERVAL</code></td><td><code>24h</code></td><td>检查证书续期的频率。</td></tr></tbody></table><p>只有当 <code>ACME_DNS_PROVIDER=cf</code> <strong>且</strong> 令牌非空时，DNS-01 才会启用。新手建议使用 Cloudflare API Token，不要使用 Global API Key；权限给 <code>区域 / 区域 / 读取</code>、<code>区域 / DNS / 读取</code>、<code>区域 / DNS / 编辑</code>，Zone Resources 只选择你的域名。详情请参阅 <a href="./../guides/certificates">证书与 HTTPS</a>。</p><hr><h2 id="http-传输-控制面和-agent-共享" tabindex="-1">HTTP 传输（控制面和 Agent 共享） <a class="header-anchor" href="#http-传输-控制面和-agent-共享" aria-label="Permalink to &quot;HTTP 传输（控制面和 Agent 共享）&quot;">​</a></h2><p>这些设置控制 Agent 如何连接到后端服务器。</p><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>作用</th></tr></thead><tbody><tr><td><code>NRE_HTTP_DIAL_TIMEOUT</code></td><td><code>30s</code></td><td>与上游服务器建立连接的超时时间。</td></tr><tr><td><code>NRE_HTTP_TLS_HANDSHAKE_TIMEOUT</code></td><td><code>10s</code></td><td>与上游服务器进行 TLS 握手的超时时间。</td></tr><tr><td><code>NRE_HTTP_RESPONSE_HEADER_TIMEOUT</code></td><td><code>30s</code></td><td>等待上游服务器响应头的超时时间。</td></tr><tr><td><code>NRE_HTTP_IDLE_CONN_TIMEOUT</code></td><td><code>90s</code></td><td>空闲连接保持打开的时间，之后关闭。</td></tr><tr><td><code>NRE_HTTP_KEEP_ALIVE</code></td><td><code>30s</code></td><td>上游连接的 TCP keep-alive 间隔。</td></tr><tr><td><code>NRE_HTTP_MAX_CONNS_PER_HOST</code></td><td><code>64</code></td><td>每个上游主机的最大并发连接数（代理端）。</td></tr><tr><td><code>NRE_HTTP_STREAM_RESUME_ENABLED</code></td><td><code>true</code></td><td>启用中断流/下载的自动恢复。</td></tr><tr><td><code>NRE_HTTP_STREAM_RESUME_MAX_ATTEMPTS</code></td><td><code>2</code></td><td>单个请求的最大恢复尝试次数。</td></tr><tr><td><code>NRE_HTTP_SAME_BACKEND_RETRY_ATTEMPTS</code></td><td><code>1</code></td><td>对同一后端的额外重试次数，仅适用于可重试的 HTTP 方法（GET、HEAD 等）。</td></tr><tr><td><code>NRE_BACKEND_FAILURE_BACKOFF_BASE</code></td><td><code>1s</code></td><td>后端故障后的起始退避时长。必须 ≤ 上限。</td></tr><tr><td><code>NRE_BACKEND_FAILURE_BACKOFF_LIMIT</code></td><td><code>15s</code></td><td>重复后端故障后的最大退避时长。</td></tr></tbody></table><hr><h2 id="relay" tabindex="-1">Relay <a class="header-anchor" href="#relay" aria-label="Permalink to &quot;Relay&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>作用</th></tr></thead><tbody><tr><td><code>NRE_RELAY_DIAL_TIMEOUT</code></td><td><code>5s</code></td><td>连接到上游中继节点的超时时间。</td></tr><tr><td><code>NRE_RELAY_HANDSHAKE_TIMEOUT</code></td><td><code>5s</code></td><td>中继握手的超时时间。</td></tr><tr><td><code>NRE_RELAY_FRAME_TIMEOUT</code></td><td><code>5s</code></td><td>读取或写入单个中继帧的超时时间。</td></tr><tr><td><code>NRE_RELAY_IDLE_TIMEOUT</code></td><td><code>2m</code></td><td>空闲中继连接保持打开的时间。</td></tr></tbody></table><hr><h2 id="wireguard" tabindex="-1">WireGuard <a class="header-anchor" href="#wireguard" aria-label="Permalink to &quot;WireGuard&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>作用</th></tr></thead><tbody><tr><td><code>NRE_WIREGUARD_ENABLED</code></td><td><code>true</code></td><td>启用或禁用 WireGuard 模块和 API。</td></tr><tr><td><code>NRE_WIREGUARD_AUTO_ADDRESS_POOLS</code></td><td><code>10.8.x.1/24,fd10:8:x::1/64</code></td><td>WireGuard 配置文件的自动 IP 地址池。<code>x</code> 被替换为顺序编号。</td></tr></tbody></table><hr><h2 id="流量统计" tabindex="-1">流量统计 <a class="header-anchor" href="#流量统计" aria-label="Permalink to &quot;流量统计&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>作用</th></tr></thead><tbody><tr><td><code>NRE_TRAFFIC_STATS_ENABLED</code></td><td><code>true</code></td><td>启用或禁用流量统计和配额执行。</td></tr><tr><td><code>NRE_TRAFFIC_CLEANUP_INTERVAL</code></td><td><code>24h</code></td><td>清理旧流量历史数据的频率。设置为 <code>0</code>、<code>off</code> 或 <code>disabled</code> 以禁用清理。</td></tr><tr><td><code>NRE_TRAFFIC_INTERFACES</code></td><td>空</td><td>要监控的网络接口列表，逗号分隔。空表示所有接口。</td></tr></tbody></table><p>流量配额模型请参阅 <a href="./traffic-accounting">流量统计原理</a>。</p><hr><h2 id="agent" tabindex="-1">Agent <a class="header-anchor" href="#agent" aria-label="Permalink to &quot;Agent&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>作用</th></tr></thead><tbody><tr><td><code>NRE_AGENT_ID</code></td><td><code>linux-agent</code></td><td>Agent 的唯一标识符。</td></tr><tr><td><code>NRE_AGENT_NAME</code></td><td><code>linux-agent</code></td><td>Agent 的显示名称。</td></tr><tr><td><code>NRE_AGENT_TOKEN</code></td><td><strong>必填</strong></td><td>Agent 心跳认证令牌（注册时生成）。</td></tr><tr><td><code>NRE_AGENT_VERSION</code></td><td><code>0.0.0</code></td><td>当前 Agent 版本，用于自更新比较。</td></tr><tr><td><code>NRE_MASTER_URL</code></td><td><strong>必填</strong></td><td>Agent 连接的控制面 URL。</td></tr><tr><td><code>NRE_DATA_DIR</code></td><td><code>/var/lib/nre-agent</code></td><td>Agent 存储本地数据的目录。</td></tr><tr><td><code>NRE_HEARTBEAT_INTERVAL</code></td><td><code>10s</code></td><td>Agent 向控制面发送心跳/同步请求的频率。</td></tr><tr><td><code>NRE_HTTP3_ENABLED</code></td><td><code>false</code></td><td>启用 HTTP/3（QUIC）作为入站协议。</td></tr><tr><td><code>NRE_TRAFFIC_STATS_ENABLED</code></td><td><code>true</code></td><td>在 Agent 端启用流量采集。</td></tr><tr><td><code>NRE_WIREGUARD_ENABLED</code></td><td><code>true</code></td><td>在 Agent 端启用 WireGuard。</td></tr><tr><td><code>NRE_PPROF_ADDR</code></td><td>空</td><td>pprof 调试端点的地址。需要调试构建。</td></tr></tbody></table>`,35)])])}const l=d(r,[["render",a]]);export{h as __pageData,l as default};
